@code {
    [CascadingParameter] public RadioGroup.RadioGroupContext Context { get; set; } = default!;
    /// <summary>The card's content (typically a title/description).</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }
    /// <summary>This card's value. Selected when it matches the enclosing <see cref="RadioGroup"/>'s <c>Value</c>.</summary>
    [Parameter, EditorRequired] public string Value { get; set; } = "";
    /// <summary>Additional CSS classes merged onto the card's <c>button</c> element.</summary>
    [Parameter] public string? Class { get; set; }
    /// <summary>Additional HTML attributes captured and forwarded to the card's <c>button</c> element.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _itemId = LumeoIds.New("radio-card");
    private bool _registered;
    private string? _registeredValue;
    // Selection stays Value-based (duplicate Values both show aria-checked under
    // single-select); only roving focus is per-item-id (see RadioGroup registry).
    private bool IsSelected => Context.Value == Value;

    private int Tabindex
    {
        get
        {
            if (Context.Value == Value) return 0;
            // The "no live selection" fallback must ALSO fire when Context.Value
            // matches NO registered item (triage #54) — else the group has no tab
            // stop and is keyboard-unreachable.
            var hasLiveSelection = !string.IsNullOrEmpty(Context.Value)
                && Context.Items.Any(i => i.Value == Context.Value);
            if (!hasLiveSelection
                && Context.Items.FirstOrDefault(i => !i.Disabled).Id == _itemId) return 0;
            return -1;
        }
    }

    private string CssClass => Cx.Merge(
        "flex cursor-pointer rounded-lg border-2 p-4 text-start transition-colors hover:bg-accent/60 focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-2",
        IsSelected ? "border-primary bg-primary/5" : "border-border/40",
        Class);

    protected override void OnParametersSet()
    {
        // Id-keyed register/replace (see RadioGroupItem): a Value change re-keys
        // the existing slot IN PLACE (#158 — not a remove+tail-add) and duplicate
        // Values never collapse (#56). RadioGroupCard has no Disabled parameter,
        // so its slot is always enabled.
        if (_registered && _registeredValue != Value)
            Context.Replace(_itemId, Value, false);
        else
            Context.Register(_itemId, Value, false);
        _registered = true;
        _registeredValue = Value;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender) return;
        try
        {
            await Interop.RegisterPreventDefaultKeys(
                _itemId,
                new[] { "ArrowDown", "ArrowRight", "ArrowUp", "ArrowLeft" }
                    .Select(k => new Lumeo.Services.PreventDefaultKeyRule(k)).ToArray());
            _pdRegistered = true;
        }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
        catch (InvalidOperationException) { } // JS interop unavailable during prerender
    }

    private bool _pdRegistered;

    private async Task Select() => await Context.OnSelect.InvokeAsync(Value);

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        // No Space branch: the native <button> click already runs Select.
        var direction = e.Key switch
        {
            "ArrowDown" or "ArrowRight" => 1,
            "ArrowUp" or "ArrowLeft" => -1,
            _ => 0
        };
        if (direction == 0) return;

        // Nav order from the LIVE DOM (#55) so a keyed reorder of reused cards is
        // honoured; falls back to the registry order when the probe is unavailable.
        var items = await OrderedItems();
        // Resolve "current" by this card's UNIQUE id, not by Value (#56).
        var idx = items.FindIndex(i => i.Id == _itemId);
        if (idx < 0) return;

        var next = FindNextEnabled(items, idx, direction);
        if (next is not null)
        {
            await Context.OnSelect.InvokeAsync(next.Value.Value);
            await Interop.FocusElement(next.Value.Id);
        }
    }

    // The registry reordered to live DOM order; an empty/null probe → registry order.
    // A Loose-mode JSInterop returns NULL for an unconfigured string[] call — null-guard.
    private async Task<List<(string Id, string Value, bool Disabled)>> OrderedItems()
    {
        var registry = Context.Items;
        string[]? domOrder;
        try
        {
            domOrder = await Interop.GetOrderedDescendantIds(Context.ContainerId, "[role='radio']");
        }
        catch (JSDisconnectedException) { domOrder = null; }
        catch (ObjectDisposedException) { domOrder = null; }
        catch (InvalidOperationException) { domOrder = null; }

        if (domOrder is not { Length: > 0 }) return registry;

        var byId = registry.ToDictionary(i => i.Id);
        var ordered = new List<(string Id, string Value, bool Disabled)>(registry.Count);
        foreach (var id in domOrder)
            if (byId.Remove(id, out var item)) ordered.Add(item);
        ordered.AddRange(byId.Values);
        return ordered;
    }

    private static (string Id, string Value, bool Disabled)? FindNextEnabled(
        List<(string Id, string Value, bool Disabled)> items, int currentIdx, int direction)
    {
        if (items.Count == 0) return null;
        var idx = currentIdx;
        for (var i = 0; i < items.Count; i++)
        {
            idx += direction;
            if (idx < 0) idx = items.Count - 1;
            else if (idx >= items.Count) idx = 0;
            if (idx == currentIdx) return null;
            if (!items[idx].Disabled) return items[idx];
        }
        return null;
    }

    public async ValueTask DisposeAsync()
    {
        // Unregister by the unique id so a disposed duplicate never deletes a
        // sibling's slot (#56).
        if (_registered)
            Context.Unregister(_itemId);
        if (!_pdRegistered) return;
        try
        {
            await Interop.UnregisterPreventDefaultKeys(_itemId);
        }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
        catch (InvalidOperationException) { }
    }
}

